import{_ as t,c as o,o as a,aN as l}from"./chunks/framework.BRm39z_l.js";const u=JSON.parse('{"title":"计算机网络基础","description":"","frontmatter":{},"headers":[],"relativePath":"computerNetwork/01.计算机网络基础.md","filePath":"computerNetwork/01.计算机网络基础.md"}'),r={name:"computerNetwork/01.计算机网络基础.md"};function i(n,e,s,c,p,d){return a(),o("div",null,e[0]||(e[0]=[l('<h1 id="计算机网络基础" tabindex="-1">计算机网络基础 <a class="header-anchor" href="#计算机网络基础" aria-label="Permalink to &quot;计算机网络基础&quot;">​</a></h1><nav class="table-of-contents"><ul><li><a href="#计算机网络体系结构">计算机网络体系结构</a><ul><li><a href="#osi七层模型">OSI七层模型</a></li><li><a href="#tcp-ip四层模型">TCP/IP四层模型</a></li></ul></li><li><a href="#数据在各层之间是怎么传输的">数据在各层之间是怎么传输的</a></li></ul></nav><h2 id="计算机网络体系结构" tabindex="-1">计算机网络体系结构 <a class="header-anchor" href="#计算机网络体系结构" aria-label="Permalink to &quot;计算机网络体系结构&quot;">​</a></h2><p>计算机网络体系结构通过将复杂的网络通信分解成不同的层次，来标准化<code>交互</code>的过程</p><p>常见的模型包括 OSI 七层模型、TCP/IP 四层模型和五层体系结构</p><p>OSI 是理论上的网络通信模型，TCP/IP 是实际应用层面上的网络通信模型</p><h3 id="osi七层模型" tabindex="-1">OSI七层模型 <a class="header-anchor" href="#osi七层模型" aria-label="Permalink to &quot;OSI七层模型&quot;">​</a></h3><ul><li><strong>应用层</strong>：最靠近用户的层，负责处理特定的应用程序细节。这一层提供了<code>网络服务</code>与<code>用户应用</code>之间的接口。例如，Web 浏览器、FTP 客户端和服务器、电子邮件客户端等。</li><li><strong>表示层</strong>：确保从一个系统发送的信息可以被另一个系统的应用层读取。它负责数据的转换、压缩和加密。例如，确保数据从一种编码格式转换为另一种，如 ASCII 到 EBCDIC。</li><li><strong>会话层</strong>：管理用户的会话，控制网络上两节点间的对话和数据交换的管理。它负责建立、维护和终止会话。例如，建立一个会话令牌，以便在网络上的两个节点之间传递。</li><li><strong>传输层</strong>：提供端到端的通信服务，保证数据的完整性和正确顺序。这一层包括 TCP 和 UDP 等。</li><li><strong>网络层</strong>：负责在多个网络之间进行数据传输，确保数据能够在复杂的网络结构中找到从源到目的地的最佳路径。这层使用的是 IP（Internet Protocol）协议。</li><li><strong>数据链路层</strong>：在物理连接中提供可靠的传输，负责建立和维护两个相邻节点间的链路。包括帧同步、MAC（媒体访问控制）。</li><li><strong>物理层</strong>：负责在物理媒介上实现原始的数据传输，比如电缆、光纤和无线信号传输。涉及的内容包括电压、接口、针脚、电缆的规格和传输速率等。</li></ul><h3 id="tcp-ip四层模型" tabindex="-1">TCP/IP四层模型 <a class="header-anchor" href="#tcp-ip四层模型" aria-label="Permalink to &quot;TCP/IP四层模型&quot;">​</a></h3><p>TCP/IP 四层模型是互联网通信的核心，定义了一系列协议和标准，确保设备间可以可靠地进行数据传输</p><ul><li><p><strong>应用层（Application Layer）</strong>：直接面向用户和应用程序，提供各种网络服务。它包含了用于特定应用的协议和服务，如 HTTP（HyperText Transfer Protocol）、FTP（File Transfer Protocol）、SMTP（Simple Mail Transfer Protocol）等。</p><blockquote><p>当在浏览器中输入一个 URL 并访问一个网页时，浏览器使用 HTTP 协议从 Web 服务器请求页面内容。</p></blockquote></li><li><p><strong>传输层（Transport Layer）</strong>：提供端到端的通信服务，确保数据可靠传输。它负责分段数据、流量控制、错误检测和纠正。常见的传输层协议有 TCP 和 UDP。</p><blockquote><p>当发送一封电子邮件时，TCP 协议确保邮件从你的客户端可靠地传输到邮件服务器。</p></blockquote></li><li><p><strong>网际层</strong>：或者叫网络层（Internet Layer），负责在不同网络之间路由数据包，提供逻辑地址（IP 地址）和网络寻址功能。用于处理数据包的分组、转发和路由选择，确保数据可以从源端传输到目标端。</p><p>常见协议：IPv4、IPv6、ICMP（Internet Control Message Protocol）。</p></li><li><blockquote><p>当访问一个网站时，网络层协议（如 IPv4）将你的请求从你的计算机通过多个路由器传输到目标服务器。</p></blockquote></li><li><p><strong>网络接口层（Network Access Layer）</strong>：或者叫链路层（Link Layer），负责将数字信号在物理通道（网线）中准确传输，定义了如何在单一网络链路上传输数据，如何处理数据帧的发送和接收，包括物理地址（MAC 地址）的解析</p><p>常见协议：以太网（Ethernet）、Wi-Fi。</p><blockquote><p>在一个局域网（LAN）中，计算机通过以太网连接交换机，链路层协议负责数据帧在网络设备间的传输。</p></blockquote></li></ul><p><img src="https://cdn.paicoding.com/tobebetterjavaer/images/nice-article/weixin-mianznxjsjwllsewswztwxxssc-ad64bbac-e0d5-4286-9b77-d008e8c8d419.jpg" alt="各层网络对应的网络协议" loading="lazy"></p><h2 id="数据在各层之间是怎么传输的" tabindex="-1">数据在各层之间是怎么传输的 <a class="header-anchor" href="#数据在各层之间是怎么传输的" aria-label="Permalink to &quot;数据在各层之间是怎么传输的&quot;">​</a></h2><p>对于发送方而言，从上层到下层层层包装，对于接收方而言，从下层到上层，层层解开包装。</p><ul><li>发送方的应用进程向接收方的应用进程传送数据</li><li>AP 先将数据交给本主机的应用层，应用层加上本层的控制信息 H5 就变成了下一层的数据单元</li><li>传输层收到这个数据单元后，加上本层的控制信息 H4，再交给网络层，成为网络层的数据单元</li><li>到了数据链路层，控制信息被分成两部分，分别加到本层数据单元的首部（H2）和尾部（T2）</li><li>最后的物理层，进行比特流的传输</li></ul><p><img src="https://cdn.paicoding.com/tobebetterjavaer/images/nice-article/weixin-mianznxjsjwllsewswztwxxssc-6e4a8326-992c-442a-8265-5dc3d179b689.jpg" alt="" loading="lazy"></p>',16)]))}const g=t(r,[["render",i]]);export{u as __pageData,g as default};
